contracts/TitanLockerManagerV1.sol.content:
// SPDX-License-Identifier: GPL-3.0-or-later

/**
  ___________________    _   __   __    ____  ________ __ __________
 /_  __/  _/_  __/   |  / | / /  / /   / __ \/ ____/ //_// ____/ __ \
  / /  / /  / / / /| | /  |/ /  / /   / / / / /   / ,<  / __/ / /_/ /
 / / _/ /  / / / ___ |/ /|  /  / /___/ /_/ / /___/ /| |/ /___/ _, _/
/_/ /___/ /_/ /_/  |_/_/ |_/  /_____/\____/\____/_/ |_/_____/_/ |_|

  Locker manager / factory
*/
pragma solidity 0.8.30;

import { ReentrancyGuard } from "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import { SafeERC20 } from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import { IERC20 } from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import { ITitanLockerManagerV1 } from "./ITitanLockerManagerV1.sol";
import { Ownable } from "./Ownable.sol";
import { TitanLockerV1 } from "./TitanLockerV1.sol";

/// @notice Deploys and indexes `TitanLockerV1` instances. Charges a creation
/// fee that the caller may pay either in ETH (locking 100% of the deposit)
/// or by letting a percentage of the deposited token itself be taken as the fee.
contract TitanLockerManagerV1 is ITitanLockerManagerV1, Ownable, ReentrancyGuard {
  using SafeERC20 for IERC20;

  error CreationDisabled();
  error IncorrectEthFee(uint256 expected, uint256 received);
  error ExemptAccountsPayNoEth();
  error TokenFeeTooHigh();
  error CallerIsNotLocker(uint40 id, address caller);
  error EthTransferFailed();

  uint16 private constant BPS_DENOMINATOR = 10000;

  bool private _creationEnabled = true;
  uint40 private _tokenLockerCount;

  mapping(uint40 => TitanLockerV1) private _tokenLockers;
  /// @dev Lets the frontend search lockers by creator, locked token, locker
  /// address, or (for LP tokens) either underlying paired token.
  mapping(address => uint40[]) private _tokenLockersForAddress;

  uint256 private _ethFee;
  uint16 private _tokenFeeBps;
  address payable private _feeReceiver;
  mapping(address => bool) private _feeExempt;

  constructor(address payable feeReceiver_) Ownable(_msgSender()) {
    if (feeReceiver_ == address(0)) revert ZeroAddress();
    _feeReceiver = feeReceiver_;
    // starting values match the fee already on file for lock creation in the
    // upstream project's fee schedule; both are adjustable via setters below.
    _ethFee = 0.2 ether;
    _tokenFeeBps = 500; // 5.00%
  }

  modifier allowCreation() {
    if (!_creationEnabled) revert CreationDisabled();
    _;
  }

  // --- core locker lifecycle ---

  function tokenLockerCount() external view override returns (uint40) {
    return _tokenLockerCount;
  }

  function creationEnabled() external view override returns (bool) {
    return _creationEnabled;
  }

  /// @dev Turns off new locks so users can be migrated to a future version.
  /// Existing locks can still be extended/deposited/withdrawn as normal.
  function setCreationEnabled(bool value_) external override onlyOwner {
    _creationEnabled = value_;
  }

  function createTokenLocker(
    address tokenAddress_,
    uint256 amount_,
    uint40 unlockTime_
  ) external payable override allowCreation nonReentrant {
    uint40 id = _tokenLockerCount++;
    uint256 amountToLock = _collectFee(id, tokenAddress_, amount_);

    TitanLockerV1 locker = new TitanLockerV1(address(this), id, _msgSender(), tokenAddress_, unlockTime_);
    _tokenLockers[id] = locker;

    IERC20(tokenAddress_).safeTransferFrom(_msgSender(), address(locker), amountToLock);

    _indexNewLocker(id, tokenAddress_, unlockTime_, locker);
  }

  /// @dev Either takes the flat `_ethFee` (100% of `amount_` gets locked), or -
  /// when no ETH is sent - deducts `_tokenFeeBps` from `amount_` in the token
  /// itself. Exempt accounts pay nothing and must not send ETH.
  function _collectFee(uint40 id_, address tokenAddress_, uint256 amount_) private returns (uint256 amountToLock) {
    bool paidInEth = msg.value != 0;

    if (_feeExempt[_msgSender()]) {
      if (paidInEth) revert ExemptAccountsPayNoEth();
      return amount_;
    }

    if (paidInEth) {
      if (msg.value != _ethFee) revert IncorrectEthFee(_ethFee, msg.value);
      (bool success, ) = _feeReceiver.call{value: msg.value}("");
      if (!success) revert EthTransferFailed();
      emit FeeCollected(id_, true, msg.value);
      return amount_;
    }

    uint256 tokenFeeAmount = (amount_ * _tokenFeeBps) / BPS_DENOMINATOR;
    amountToLock = amount_ - tokenFeeAmount;

    if (tokenFeeAmount != 0) {
      IERC20(tokenAddress_).safeTransferFrom(_msgSender(), _feeReceiver, tokenFeeAmount);
      emit FeeCollected(id_, false, tokenFeeAmount);
    }
  }

  /// @dev Records the new locker in every address-keyed search bucket the
  /// frontend looks lockers up by, then announces creation.
  function _indexNewLocker(uint40 id_, address tokenAddress_, uint40 unlockTime_, TitanLockerV1 locker_) private {
    address lockerAddress = address(locker_);

    _tokenLockersForAddress[_msgSender()].push(id_);
    _tokenLockersForAddress[tokenAddress_].push(id_);
    _tokenLockersForAddress[lockerAddress].push(id_);

    (bool hasLpData, , address token0Address, address token1Address, , , , ) = locker_.getLpData();
    if (hasLpData) {
      _tokenLockersForAddress[token0Address].push(id_);
      _tokenLockersForAddress[token1Address].push(id_);
    }

    emit TokenLockerCreated(
      id_,
      tokenAddress_,
      token0Address,
      token1Address,
      _msgSender(),
      IERC20(tokenAddress_).balanceOf(lockerAddress),
      unlockTime_
    );
  }

  function getTokenLockAddress(uint40 id_) external view override returns (address) {
    return address(_tokenLockers[id_]);
  }

  function getTokenLockData(uint40 id_) external view override returns (
    bool isLpToken,
    uint40 id,
    address contractAddress,
    address lockOwner,
    address token,
    address createdBy,
    uint40 createdAt,
    uint40 unlockTime,
    uint256 balance,
    uint256 totalSupply
  ) {
    return _tokenLockers[id_].getLockData();
  }

  function getLpData(uint40 id_) external view override returns (
    bool hasLpData,
    uint40 id,
    address token0,
    address token1,
    uint256 balance0,
    uint256 balance1,
    uint256 price0,
    uint256 price1
  ) {
    return _tokenLockers[id_].getLpData();
  }

  function getTokenLockersForAddress(address address_) external view override returns (uint40[] memory) {
    return _tokenLockersForAddress[address_];
  }

  /// @dev Called by a `TitanLockerV1` whenever its ownership changes, so the
  /// search index above stays accurate.
  function notifyLockerOwnerChange(
    uint40 id_,
    address newOwner_,
    address previousOwner_,
    address createdBy_
  ) external override {
    if (_msgSender() != address(_tokenLockers[id_])) revert CallerIsNotLocker(id_, _msgSender());

    if (previousOwner_ != createdBy_) {
      uint40[] storage previousOwnerLocks = _tokenLockersForAddress[previousOwner_];
      for (uint256 i = 0; i < previousOwnerLocks.length; i++) {
        if (previousOwnerLocks[i] != id_) continue;
        previousOwnerLocks[i] = previousOwnerLocks[previousOwnerLocks.length - 1];
        previousOwnerLocks.pop();
        break;
      }
    }

    uint40[] storage newOwnerLocks = _tokenLockersForAddress[newOwner_];
    for (uint256 i = 0; i < newOwnerLocks.length; i++) {
      if (newOwnerLocks[i] == id_) return;
    }
    newOwnerLocks.push(id_);
  }

  // --- fee configuration ---

  function ethFee() external view override returns (uint256) {
    return _ethFee;
  }

  function tokenFeeBps() external view override returns (uint16) {
    return _tokenFeeBps;
  }

  function feeReceiver() external view override returns (address) {
    return _feeReceiver;
  }

  function isExemptFromFees(address account_) external view override returns (bool) {
    return _feeExempt[account_];
  }

  function setEthFee(uint256 value_) external override onlyOwner {
    _ethFee = value_;
    emit FeeConfigUpdated(_ethFee, _tokenFeeBps, _feeReceiver);
  }

  function setTokenFeeBps(uint16 value_) external override onlyOwner {
    if (value_ > BPS_DENOMINATOR) revert TokenFeeTooHigh();
    _tokenFeeBps = value_;
    emit FeeConfigUpdated(_ethFee, _tokenFeeBps, _feeReceiver);
  }

  function setFeeReceiver(address payable value_) external override onlyOwner {
    if (value_ == address(0)) revert ZeroAddress();
    _feeReceiver = value_;
    emit FeeConfigUpdated(_ethFee, _tokenFeeBps, _feeReceiver);
  }

  function setFeeExempt(address account_, bool exempt_) external override onlyOwner {
    _feeExempt[account_] = exempt_;
  }
}

contracts/TitanLockerManagerV2.sol.content:
// SPDX-License-Identifier: GPL-3.0-or-later

/**
  ___________________    _   __   __    ____  ________ __ __________
 /_  __/  _/_  __/   |  / | / /  / /   / __ \/ ____/ //_// ____/ __ \
  / /  / /  / / / /| | /  |/ /  / /   / / / / /   / ,<  / __/ / /_/ /
 / / _/ /  / / / ___ |/ /|  /  / /___/ /_/ / /___/ /| |/ /___/ _, _/
/_/ /___/ /_/ /_/  |_/_/ |_/  /_____/\____/\____/_/ |_/_____/_/ |_|

  Locker manager / factory (V2 - tokens + V2/V3/V4 LP)
*/
pragma solidity 0.8.30;

import { ReentrancyGuard } from "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import { SafeERC20 } from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import { IERC20 } from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import { IERC721 } from "@openzeppelin/contracts/token/ERC721/IERC721.sol";
import { ITitanLockerManagerV2 } from "./ITitanLockerManagerV2.sol";
import { Ownable } from "./Ownable.sol";
import { TitanLockerV2 } from "./TitanLockerV2.sol";

/// @notice Deploys and indexes `TitanLockerV2` instances for three lock kinds -
/// plain/LP ERC20 tokens, Uniswap V3 positions, and Uniswap V4 positions - all
/// through one manager. Each lock is its own child contract, so custody is
/// isolated per lock. V3/V4 positions can only be locked against a
/// position manager the owner has allowlisted, which is both the multichain
/// mechanism and the kill-switch for un-validated integrations.
contract TitanLockerManagerV2 is ITitanLockerManagerV2, Ownable, ReentrancyGuard {
  using SafeERC20 for IERC20;

  error CreationDisabled();
  error IncorrectEthFee(uint256 expected, uint256 received);
  error ExemptAccountsPayNoEth();
  error TokenFeeTooHigh();
  error CallerIsNotLocker(uint40 id, address caller);
  error EthTransferFailed();
  error PositionManagerNotAllowed(address positionManager);
  error InvalidPositionManagerKind();
  error InvalidVestingSchedule();
  error TokenFeeExceedsCallerMax(uint16 liveTokenFeeBps, uint16 maxTokenFeeBps);
  error ZeroAmount();

  uint16 private constant BPS_DENOMINATOR = 10000;
  /// @dev Hard ceiling on the owner-settable token fee, independent of any
  /// caller-side slippage protection. Bounds the worst case of a fee change
  /// landing between a user's createTokenLock/createVestingLock submission
  /// and its mining: at most 5% of the deposit, never up to 100%.
  uint16 private constant MAX_TOKEN_FEE_BPS = 500;

  bool private _creationEnabled = true;
  uint40 private _tokenLockerCount;

  mapping(uint40 => TitanLockerV2) private _tokenLockers;
  /// @dev Lets the frontend search lockers by creator, locked token/position
  /// manager, locker address, or either underlying paired token.
  mapping(address => uint40[]) private _tokenLockersForAddress;

  /// @dev Allowlist of Uniswap position managers. `_pmKind` records whether a
  /// manager is V3- or V4-style; `_pmAllowed` gates whether new locks may use
  /// it. A manager with `_pmAllowed == false` is rejected regardless of kind.
  mapping(address => LockKind) private _pmKind;
  mapping(address => bool) private _pmAllowed;

  uint256 private _ethFee;
  uint16 private _tokenFeeBps;
  address payable private _feeReceiver;
  mapping(address => bool) private _feeExempt;

  constructor(address payable feeReceiver_) Ownable(_msgSender()) {
    if (feeReceiver_ == address(0)) revert ZeroAddress();
    _feeReceiver = feeReceiver_;
    // same starting fee schedule as V1; both adjustable via the setters below.
    _ethFee = 0.2 ether;
    _tokenFeeBps = 500; // 5.00%
  }

  modifier allowCreation() {
    if (!_creationEnabled) revert CreationDisabled();
    _;
  }

  // --- config ---

  function tokenLockerCount() external view override returns (uint40) {
    return _tokenLockerCount;
  }

  function creationEnabled() external view override returns (bool) {
    return _creationEnabled;
  }

  /// @dev Turns off new locks so users can be migrated to a future version.
  /// Existing locks keep working (extend/deposit/withdraw/collect) as normal.
  function setCreationEnabled(bool value_) external override onlyOwner {
    _creationEnabled = value_;
  }

  // --- position-manager allowlist ---

  function positionManagerKind(address positionManager_) external view override returns (LockKind kind, bool allowed) {
    return (_pmKind[positionManager_], _pmAllowed[positionManager_]);
  }

  function setPositionManager(address positionManager_, LockKind kind_, bool allowed_) external override onlyOwner {
    if (positionManager_ == address(0)) revert ZeroAddress();
    if (kind_ != LockKind.UNIV3 && kind_ != LockKind.UNIV4) revert InvalidPositionManagerKind();
    _pmKind[positionManager_] = kind_;
    _pmAllowed[positionManager_] = allowed_;
    emit PositionManagerSet(positionManager_, kind_, allowed_);
  }

  // --- ERC20 lock creation ---

  function createTokenLock(
    address tokenAddress_,
    uint256 amount_,
    uint40 unlockTime_,
    uint16 maxTokenFeeBps_
  ) external payable override allowCreation nonReentrant {
    if (amount_ == 0) revert ZeroAmount();

    uint40 id = _tokenLockerCount++;
    uint256 amountToLock = _collectFee(id, tokenAddress_, amount_, maxTokenFeeBps_);

    TitanLockerV2 locker = new TitanLockerV2(
      address(this), id, _msgSender(), LockKind.ERC20, tokenAddress_, 0, unlockTime_, 0, 0, 0, 0
    );
    _tokenLockers[id] = locker;

    IERC20(tokenAddress_).safeTransferFrom(_msgSender(), address(locker), amountToLock);

    _indexNewLocker(id, tokenAddress_, locker);

    (, address token0, address token1) = locker.getUnderlyingTokens();
    _indexUnderlying(id, token0, token1);

    emit TokenLockerCreated(
      id,
      tokenAddress_,
      token0,
      token1,
      _msgSender(),
      IERC20(tokenAddress_).balanceOf(address(locker)),
      unlockTime_
    );
  }

  /// @dev Either takes the flat `_ethFee` (100% of `amount_` gets locked), or -
  /// when no ETH is sent - deducts `_tokenFeeBps` from `amount_` in the token
  /// itself, reverting if the live rate exceeds the caller's own
  /// `maxTokenFeeBps_` ceiling (protects against a fee change landing between
  /// submission and mining - the same role `amountOutMin` plays on a swap).
  /// Exempt accounts pay nothing and must not send ETH.
  function _collectFee(
    uint40 id_,
    address tokenAddress_,
    uint256 amount_,
    uint16 maxTokenFeeBps_
  ) private returns (uint256 amountToLock) {
    bool paidInEth = msg.value != 0;

    if (_feeExempt[_msgSender()]) {
      if (paidInEth) revert ExemptAccountsPayNoEth();
      return amount_;
    }

    if (paidInEth) {
      if (msg.value != _ethFee) revert IncorrectEthFee(_ethFee, msg.value);
      (bool success, ) = _feeReceiver.call{value: msg.value}("");
      if (!success) revert EthTransferFailed();
      emit FeeCollected(id_, true, msg.value);
      return amount_;
    }

    if (_tokenFeeBps > maxTokenFeeBps_) revert TokenFeeExceedsCallerMax(_tokenFeeBps, maxTokenFeeBps_);

    // Round the fee up (ceiling division) instead of down, so any nonzero
    // amount_ at a nonzero fee rate always pays at least 1 unit - dust
    // amounts can no longer round down to a free lock.
    uint256 tokenFeeAmount = (amount_ * _tokenFeeBps + BPS_DENOMINATOR - 1) / BPS_DENOMINATOR;
    amountToLock = amount_ - tokenFeeAmount;

    if (tokenFeeAmount != 0) {
      IERC20(tokenAddress_).safeTransferFrom(_msgSender(), _feeReceiver, tokenFeeAmount);
      emit FeeCollected(id_, false, tokenFeeAmount);
    }
  }

  // --- vesting lock creation ---

  /// @dev Locks a fungible token and releases it linearly (with an optional
  /// cliff) to the lock owner between `start_` and `end_`. Same creation-fee
  /// options as `createTokenLock`; the vesting grant is the post-fee amount and
  /// is irrevocable.
  function createVestingLock(
    address tokenAddress_,
    uint256 amount_,
    uint40 start_,
    uint40 cliff_,
    uint40 end_,
    uint16 maxTokenFeeBps_
  ) external payable override allowCreation nonReentrant {
    if (amount_ == 0) revert ZeroAmount();
    if (start_ >= end_ || cliff_ < start_ || cliff_ > end_ || end_ <= uint40(block.timestamp)) {
      revert InvalidVestingSchedule();
    }

    uint40 id = _tokenLockerCount++;
    uint256 amountToLock = _collectFee(id, tokenAddress_, amount_, maxTokenFeeBps_);

    // Grant is the nominal post-fee amount; `release()` clamps payouts to the
    // lock's live balance, so fee-on-transfer shortfalls can never over-release.
    TitanLockerV2 locker = new TitanLockerV2(
      address(this), id, _msgSender(), LockKind.ERC20_VESTING, tokenAddress_, 0, end_, start_, cliff_, end_, amountToLock
    );
    _tokenLockers[id] = locker;

    IERC20(tokenAddress_).safeTransferFrom(_msgSender(), address(locker), amountToLock);

    _indexNewLocker(id, tokenAddress_, locker);

    (, address token0, address token1) = locker.getUnderlyingTokens();
    _indexUnderlying(id, token0, token1);

    emit VestingLockerCreated(id, tokenAddress_, token0, token1, _msgSender(), amountToLock, start_, cliff_, end_);
  }

  // --- V3/V4 position lock creation ---

  function createPositionLock(
    address positionManager_,
    uint256 tokenId_,
    uint40 unlockTime_
  ) external payable override allowCreation nonReentrant {
    if (!_pmAllowed[positionManager_]) revert PositionManagerNotAllowed(positionManager_);
    LockKind kind = _pmKind[positionManager_];

    uint40 id = _tokenLockerCount++;
    _collectEthFee(id);

    TitanLockerV2 locker = new TitanLockerV2(
      address(this), id, _msgSender(), kind, positionManager_, tokenId_, unlockTime_, 0, 0, 0, 0
    );
    _tokenLockers[id] = locker;

    // Pull the position NFT from the depositor into the lock. Requires the
    // depositor to have approved this manager as an operator for it.
    IERC721(positionManager_).safeTransferFrom(_msgSender(), address(locker), tokenId_);

    _indexNewLocker(id, positionManager_, locker);

    (, address token0, address token1) = locker.getUnderlyingTokens();
    _indexUnderlying(id, token0, token1);

    emit PositionLockerCreated(id, kind, positionManager_, tokenId_, token0, token1, _msgSender(), unlockTime_);
  }

  /// @dev Flat-ETH-fee path used by position locks (no in-kind option exists
  /// for an NFT). Exempt accounts pay nothing and must not send ETH.
  function _collectEthFee(uint40 id_) private {
    if (_feeExempt[_msgSender()]) {
      if (msg.value != 0) revert ExemptAccountsPayNoEth();
      return;
    }

    if (msg.value != _ethFee) revert IncorrectEthFee(_ethFee, msg.value);

    if (msg.value != 0) {
      (bool success, ) = _feeReceiver.call{value: msg.value}("");
      if (!success) revert EthTransferFailed();
      emit FeeCollected(id_, true, msg.value);
    }
  }

  // --- indexing ---

  /// @dev Records a new locker in the creator / asset / locker-address buckets.
  function _indexNewLocker(uint40 id_, address asset_, TitanLockerV2 locker_) private {
    _tokenLockersForAddress[_msgSender()].push(id_);
    _tokenLockersForAddress[asset_].push(id_);
    _tokenLockersForAddress[address(locker_)].push(id_);
  }

  /// @dev Records the lock under each underlying paired token, when present.
  function _indexUnderlying(uint40 id_, address token0_, address token1_) private {
    if (token0_ != address(0)) _tokenLockersForAddress[token0_].push(id_);
    if (token1_ != address(0)) _tokenLockersForAddress[token1_].push(id_);
  }

  // --- reads ---

  function getTokenLockAddress(uint40 id_) external view override returns (address) {
    return address(_tokenLockers[id_]);
  }

  function getTokenLockData(uint40 id_) external view override returns (
    LockKind kind,
    uint40 id,
    address contractAddress,
    address lockOwner,
    address asset,
    uint256 tokenId,
    address createdBy,
    uint40 createdAt,
    uint40 unlockTime,
    uint256 balance
  ) {
    return _tokenLockers[id_].getLockData();
  }

  function getTokenLockersForAddress(address address_) external view override returns (uint40[] memory) {
    return _tokenLockersForAddress[address_];
  }

  /// @dev Called by a `TitanLockerV2` whenever its ownership changes, so the
  /// search index above stays accurate.
  function notifyLockerOwnerChange(
    uint40 id_,
    address newOwner_,
    address previousOwner_,
    address createdBy_
  ) external override {
    if (_msgSender() != address(_tokenLockers[id_])) revert CallerIsNotLocker(id_, _msgSender());

    if (previousOwner_ != createdBy_) {
      uint40[] storage previousOwnerLocks = _tokenLockersForAddress[previousOwner_];
      for (uint256 i = 0; i < previousOwnerLocks.length; i++) {
        if (previousOwnerLocks[i] != id_) continue;
        previousOwnerLocks[i] = previousOwnerLocks[previousOwnerLocks.length - 1];
        previousOwnerLocks.pop();
        break;
      }
    }

    uint40[] storage newOwnerLocks = _tokenLockersForAddress[newOwner_];
    for (uint256 i = 0; i < newOwnerLocks.length; i++) {
      if (newOwnerLocks[i] == id_) return;
    }
    newOwnerLocks.push(id_);
  }

  // --- fee configuration ---

  function ethFee() external view override returns (uint256) {
    return _ethFee;
  }

  function tokenFeeBps() external view override returns (uint16) {
    return _tokenFeeBps;
  }

  function feeReceiver() external view override returns (address) {
    return _feeReceiver;
  }

  function isExemptFromFees(address account_) external view override returns (bool) {
    return _feeExempt[account_];
  }

  function setEthFee(uint256 value_) external override onlyOwner {
    _ethFee = value_;
    emit FeeConfigUpdated(_ethFee, _tokenFeeBps, _feeReceiver);
  }

  function setTokenFeeBps(uint16 value_) external override onlyOwner {
    if (value_ > MAX_TOKEN_FEE_BPS) revert TokenFeeTooHigh();
    _tokenFeeBps = value_;
    emit FeeConfigUpdated(_ethFee, _tokenFeeBps, _feeReceiver);
  }

  function setFeeReceiver(address payable value_) external override onlyOwner {
    if (value_ == address(0)) revert ZeroAddress();
    _feeReceiver = value_;
    emit FeeConfigUpdated(_ethFee, _tokenFeeBps, _feeReceiver);
  }

  function setFeeExempt(address account_, bool exempt_) external override onlyOwner {
    _feeExempt[account_] = exempt_;
  }
}

contracts/TitanLockerV1.sol.content:
// SPDX-License-Identifier: GPL-3.0-or-later

/**
  ___________________    _   __   __    ____  ________ __ __________
 /_  __/  _/_  __/   |  / | / /  / /   / __ \/ ____/ //_// ____/ __ \
  / /  / /  / / / /| | /  |/ /  / /   / / / / /   / ,<  / __/ / /_/ /
 / / _/ /  / / / ___ |/ /|  /  / /___/ /_/ / /___/ /| |/ /___/ _, _/
/_/ /___/ /_/ /_/  |_/_/ |_/  /_____/\____/\____/_/ |_/_____/_/ |_|

  Individual token lock
*/
pragma solidity 0.8.30;

import { ReentrancyGuard } from "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import { SafeERC20 } from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import { IERC20 } from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import { ITitanLockerManagerV1 } from "./ITitanLockerManagerV1.sol";
import { Ownable } from "./Ownable.sol";
import { Util } from "./Util.sol";

/// @notice Holds one deposit of a single ERC20 (or LP) token until `unlockTime`,
/// deployed and tracked by a `TitanLockerManagerV1`.
contract TitanLockerV1 is Ownable, ReentrancyGuard {
  using SafeERC20 for IERC20;

  error UnlockTimeNotInFuture();
  error UnlockTimeCannotBeReduced();
  error LockStillActive(uint40 unlockTime);
  error CannotSweepLockedToken();
  error EthTransferFailed();

  event UnlockTimeExtended(uint40 newUnlockTime);
  event TokensDeposited(uint256 amountReceived);
  event TokensWithdrawn();

  ITitanLockerManagerV1 private immutable _manager;
  IERC20 private immutable _token;
  address private immutable _createdBy;
  uint40 private immutable _id;
  uint40 private immutable _createdAt;
  bool private immutable _isLpToken;

  uint40 private _unlockTime;

  constructor(
    address manager_,
    uint40 id_,
    address owner_,
    address tokenAddress_,
    uint40 unlockTime_
  ) Ownable(owner_) {
    if (owner_ == address(0)) revert ZeroAddress();
    if (unlockTime_ <= uint40(block.timestamp)) revert UnlockTimeNotInFuture();

    _manager = ITitanLockerManagerV1(manager_);
    _id = id_;
    _token = IERC20(tokenAddress_);
    _createdBy = owner_;
    _createdAt = uint40(block.timestamp);
    _unlockTime = unlockTime_;
    _isLpToken = Util.isLpToken(tokenAddress_);
  }

  function _heldBalance() private view returns (uint256) {
    return _token.balanceOf(address(this));
  }

  function getIsLpToken() external view returns (bool) {
    return _isLpToken;
  }

  function getLockData() external view returns (
    bool isLpToken,
    uint40 id,
    address contractAddress,
    address lockOwner,
    address token,
    address createdBy,
    uint40 createdAt,
    uint40 unlockTime,
    uint256 balance,
    uint256 totalSupply
  ) {
    isLpToken = _isLpToken;
    id = _id;
    contractAddress = address(this);
    lockOwner = _owner();
    token = address(_token);
    createdBy = _createdBy;
    createdAt = _createdAt;
    unlockTime = _unlockTime;
    balance = _heldBalance();
    totalSupply = _token.totalSupply();
  }

  function getLpData() external view returns (
    bool hasLpData,
    uint40 id,
    address token0,
    address token1,
    uint256 balance0,
    uint256 balance1,
    uint256 price0,
    uint256 price1
  ) {
    id = _id;

    if (!_isLpToken) {
      hasLpData = false;
      return (hasLpData, id, token0, token1, balance0, balance1, price0, price1);
    }

    try Util.getLpData(address(_token)) returns (
      address token0_,
      address token1_,
      uint256 balance0_,
      uint256 balance1_,
      uint256 price0_,
      uint256 price1_
    ) {
      hasLpData = true;
      token0 = token0_;
      token1 = token1_;
      balance0 = balance0_;
      balance1 = balance1_;
      price0 = price0_;
      price1 = price1_;
    } catch {
      hasLpData = false;
    }
  }

  /// @dev Top up the locked balance and/or push `unlockTime` further out, in one call.
  function deposit(uint256 amount_, uint40 newUnlockTime_) external onlyOwner nonReentrant {
    if (newUnlockTime_ != 0) {
      if (newUnlockTime_ < _unlockTime || newUnlockTime_ < uint40(block.timestamp)) {
        revert UnlockTimeCannotBeReduced();
      }
      _unlockTime = newUnlockTime_;
      emit UnlockTimeExtended(_unlockTime);
    }

    if (amount_ != 0) {
      uint256 balanceBefore = _heldBalance();
      _token.safeTransferFrom(_msgSender(), address(this), amount_);
      emit TokensDeposited(_heldBalance() - balanceBefore);
    }
  }

  function withdraw() external onlyOwner nonReentrant {
    if (uint40(block.timestamp) < _unlockTime) revert LockStillActive(_unlockTime);

    _token.safeTransfer(_owner(), _heldBalance());

    emit TokensWithdrawn();
  }

  /// @dev Rescue any token other than the one under lock (e.g. an airdrop
  /// or dividend that landed on this contract by accident).
  function withdrawToken(address tokenAddress_) external onlyOwner nonReentrant {
    if (tokenAddress_ == address(_token)) revert CannotSweepLockedToken();

    IERC20 stray = IERC20(tokenAddress_);
    stray.safeTransfer(_owner(), stray.balanceOf(address(this)));
  }

  /// @dev Rescue any ETH that landed on this contract (e.g. from a dividend token).
  function withdrawEth() external onlyOwner nonReentrant {
    (bool success, ) = payable(_owner()).call{value: address(this).balance}("");
    if (!success) revert EthTransferFailed();
  }

  function _transferOwnership(address newOwner_) internal override onlyOwner {
    address previousOwner = _owner();
    super._transferOwnership(newOwner_);

    // keep the manager's search index in sync with the new owner
    _manager.notifyLockerOwnerChange(_id, newOwner_, previousOwner, _createdBy);
  }

  /// @dev Accepts stray ETH (e.g. dividends); use `withdrawEth` to recover it.
  receive() external payable {}
}

contracts/TitanLockerV2.sol.content:
// SPDX-License-Identifier: GPL-3.0-or-later

/**
  ___________________    _   __   __    ____  ________ __ __________
 /_  __/  _/_  __/   |  / | / /  / /   / __ \/ ____/ //_// ____/ __ \
  / /  / /  / / / /| | /  |/ /  / /   / / / / /   / ,<  / __/ / /_/ /
 / / _/ /  / / / ___ |/ /|  /  / /___/ /_/ / /___/ /| |/ /___/ _, _/
/_/ /___/ /_/ /_/  |_/_/ |_/  /_____/\____/\____/_/ |_/_____/_/ |_|

  Individual lock - holds one ERC20 balance OR one V3/V4 LP position
*/
pragma solidity 0.8.30;

import { ReentrancyGuard } from "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import { SafeERC20 } from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import { IERC20 } from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import { IERC721 } from "@openzeppelin/contracts/token/ERC721/IERC721.sol";
import { ERC721Holder } from "@openzeppelin/contracts/token/ERC721/utils/ERC721Holder.sol";
import { ITitanLockerManagerV2 } from "./ITitanLockerManagerV2.sol";
import { INonfungiblePositionManagerV3 } from "./interfaces/INonfungiblePositionManagerV3.sol";
import { IPositionManagerV4, PoolKeyV4, ActionsV4 } from "./interfaces/IPositionManagerV4.sol";
import { Ownable } from "./Ownable.sol";
import { Util } from "./Util.sol";

/// @notice Holds exactly one asset until `unlockTime`: either a single ERC20
/// (plain token or V2-style LP token) balance, or a single Uniswap V3/V4 LP
/// position NFT. For NFT locks the owner may `collectFees` at any time while
/// the position stays locked. Deployed and tracked by a `TitanLockerManagerV2`.
///
/// @dev Custody is isolated by construction: one deployed instance holds one
/// asset, `_kind`/`_asset`/`_tokenId` are immutable, and every value-moving
/// entry point is `onlyOwner`. There is no shared balance or ledger, so no
/// lock can ever touch another lock's funds or fees.
contract TitanLockerV2 is Ownable, ERC721Holder, ReentrancyGuard {
  using SafeERC20 for IERC20;

  error UnlockTimeNotInFuture();
  error UnlockTimeCannotBeReduced();
  error LockStillActive(uint40 unlockTime);
  error CannotSweepLockedToken();
  error EthTransferFailed();
  error WrongLockKind();
  error InvalidVestingSchedule();

  event UnlockTimeExtended(uint40 newUnlockTime);
  event TokensDeposited(uint256 amountReceived);
  event TokensWithdrawn();
  event PositionWithdrawn(uint256 tokenId);
  event FeesCollected(uint256 amount0, uint256 amount1);
  event StrayNftRescued(address indexed collection, uint256 tokenId);
  event TokensReleased(uint256 amount);

  ITitanLockerManagerV2.LockKind private immutable _kind;
  ITitanLockerManagerV2 private immutable _manager;
  /// @dev ERC20 token address for ERC20 locks; position-manager address for
  /// V3/V4 locks.
  address private immutable _asset;
  /// @dev The position NFT id for V3/V4 locks; unused (0) for ERC20 locks.
  uint256 private immutable _tokenId;
  address private immutable _createdBy;
  uint40 private immutable _id;
  uint40 private immutable _createdAt;
  /// @dev Only meaningful for ERC20/vesting locks - true if the token is a V2 LP pair.
  bool private immutable _isLpToken;

  /// @dev Vesting schedule (ERC20_VESTING kind only; all zero otherwise).
  /// `_vestTotal` is the nominal granted amount; `_released` is the running
  /// total already sent to the owner.
  uint40 private immutable _vestStart;
  uint40 private immutable _vestCliff;
  uint40 private immutable _vestEnd;
  uint256 private immutable _vestTotal;
  uint256 private _released;

  uint40 private _unlockTime;

  constructor(
    address manager_,
    uint40 id_,
    address owner_,
    ITitanLockerManagerV2.LockKind kind_,
    address asset_,
    uint256 tokenId_,
    uint40 unlockTime_,
    uint40 vestStart_,
    uint40 vestCliff_,
    uint40 vestEnd_,
    uint256 vestTotal_
  ) Ownable(owner_) {
    if (owner_ == address(0)) revert ZeroAddress();
    if (unlockTime_ <= uint40(block.timestamp)) revert UnlockTimeNotInFuture();

    bool isVesting = kind_ == ITitanLockerManagerV2.LockKind.ERC20_VESTING;
    bool isFungible = isVesting || kind_ == ITitanLockerManagerV2.LockKind.ERC20;

    if (isVesting) {
      // start < end, and start <= cliff <= end. (unlockTime_ is set to end by
      // the manager, so the future-time check above already covers end.)
      if (vestStart_ >= vestEnd_ || vestCliff_ < vestStart_ || vestCliff_ > vestEnd_) {
        revert InvalidVestingSchedule();
      }
    }

    _manager = ITitanLockerManagerV2(manager_);
    _id = id_;
    _kind = kind_;
    _asset = asset_;
    _tokenId = tokenId_;
    _createdBy = owner_;
    _createdAt = uint40(block.timestamp);
    _unlockTime = unlockTime_;
    _isLpToken = isFungible && Util.isLpToken(asset_);

    _vestStart = vestStart_;
    _vestCliff = vestCliff_;
    _vestEnd = vestEnd_;
    _vestTotal = vestTotal_;
  }

  modifier onlyErc20() {
    if (_kind != ITitanLockerManagerV2.LockKind.ERC20) revert WrongLockKind();
    _;
  }

  modifier onlyPosition() {
    if (
      _kind != ITitanLockerManagerV2.LockKind.UNIV3 &&
      _kind != ITitanLockerManagerV2.LockKind.UNIV4
    ) revert WrongLockKind();
    _;
  }

  modifier onlyVesting() {
    if (_kind != ITitanLockerManagerV2.LockKind.ERC20_VESTING) revert WrongLockKind();
    _;
  }

  function _isFungible() private view returns (bool) {
    return _kind == ITitanLockerManagerV2.LockKind.ERC20
      || _kind == ITitanLockerManagerV2.LockKind.ERC20_VESTING;
  }

  // --- reads ---

  function _heldBalance() private view returns (uint256) {
    if (!_isFungible()) return 0;
    return IERC20(_asset).balanceOf(address(this));
  }

  function getKind() external view returns (ITitanLockerManagerV2.LockKind) {
    return _kind;
  }

  function getLockData() external view returns (
    ITitanLockerManagerV2.LockKind kind,
    uint40 id,
    address contractAddress,
    address lockOwner,
    address asset,
    uint256 tokenId,
    address createdBy,
    uint40 createdAt,
    uint40 unlockTime,
    uint256 balance
  ) {
    kind = _kind;
    id = _id;
    contractAddress = address(this);
    lockOwner = _owner();
    asset = _asset;
    tokenId = _tokenId;
    createdBy = _createdBy;
    createdAt = _createdAt;
    unlockTime = _unlockTime;
    balance = _heldBalance();
  }

  /// @notice The two underlying tokens of the locked asset, best-effort.
  /// V2 LP: the pair's `token0`/`token1`. V3/V4: the position's two tokens.
  /// Plain ERC20 or on any read failure: both zero with `hasData == false`.
  function getUnderlyingTokens() public view returns (bool hasData, address token0, address token1) {
    if (_isFungible()) {
      if (!_isLpToken) return (false, address(0), address(0));
      try Util.getLpData(_asset) returns (address t0, address t1, uint256, uint256, uint256, uint256) {
        return (true, t0, t1);
      } catch {
        return (false, address(0), address(0));
      }
    }

    if (_kind == ITitanLockerManagerV2.LockKind.UNIV3) {
      try INonfungiblePositionManagerV3(_asset).positions(_tokenId) returns (
        uint96, address, address t0, address t1, uint24, int24, int24, uint128, uint256, uint256, uint128, uint128
      ) {
        return (true, t0, t1);
      } catch {
        return (false, address(0), address(0));
      }
    }

    // UNIV4
    try IPositionManagerV4(_asset).getPoolAndPositionInfo(_tokenId) returns (PoolKeyV4 memory key, uint256) {
      return (true, key.currency0, key.currency1);
    } catch {
      return (false, address(0), address(0));
    }
  }

  // --- unlock-time management (all kinds) ---

  /// @dev Push `unlockTime` further out. Never allowed to reduce it. Not
  /// available for vesting locks - their schedule is fixed at creation.
  function extendLock(uint40 newUnlockTime_) public onlyOwner {
    if (_kind == ITitanLockerManagerV2.LockKind.ERC20_VESTING) revert WrongLockKind();
    if (newUnlockTime_ < _unlockTime || newUnlockTime_ < uint40(block.timestamp)) {
      revert UnlockTimeCannotBeReduced();
    }
    _unlockTime = newUnlockTime_;
    emit UnlockTimeExtended(_unlockTime);
  }

  // --- ERC20 lock lifecycle ---

  /// @dev Top up the locked balance and/or push `unlockTime` further out.
  function deposit(uint256 amount_, uint40 newUnlockTime_) external onlyOwner onlyErc20 nonReentrant {
    if (newUnlockTime_ != 0) extendLock(newUnlockTime_);

    if (amount_ != 0) {
      uint256 balanceBefore = _heldBalance();
      IERC20(_asset).safeTransferFrom(_msgSender(), address(this), amount_);
      emit TokensDeposited(_heldBalance() - balanceBefore);
    }
  }

  // --- V3/V4 position fee claiming ---

  /// @notice Collect the trading fees accrued to the locked position and send
  /// them to the lock owner. Callable any time while the lock is active - this
  /// is the whole point of locking an LP position. Touches only this lock's own
  /// immutable `_tokenId`, so it can never reach another lock's fees.
  function collectFees() external onlyOwner onlyPosition nonReentrant returns (uint256 amount0, uint256 amount1) {
    address recipient = _owner();

    if (_kind == ITitanLockerManagerV2.LockKind.UNIV3) {
      (amount0, amount1) = INonfungiblePositionManagerV3(_asset).collect(
        INonfungiblePositionManagerV3.CollectParams({
          tokenId: _tokenId,
          recipient: recipient,
          amount0Max: type(uint128).max,
          amount1Max: type(uint128).max
        })
      );
    } else {
      // UNIV4: decrease liquidity by zero (realises fees) then take both
      // currencies straight to the owner. modifyLiquidities doesn't return the
      // amounts taken, so capture them as the recipient's balance delta -
      // native ETH (currency == address(0)) and ERC20s read differently.
      (PoolKeyV4 memory key, ) = IPositionManagerV4(_asset).getPoolAndPositionInfo(_tokenId);

      uint256 balance0Before = _currencyBalance(key.currency0, recipient);
      uint256 balance1Before = _currencyBalance(key.currency1, recipient);

      bytes memory actions = abi.encodePacked(ActionsV4.DECREASE_LIQUIDITY, ActionsV4.TAKE_PAIR);
      bytes[] memory params = new bytes[](2);
      params[0] = abi.encode(_tokenId, uint256(0), uint128(0), uint128(0), bytes(""));
      params[1] = abi.encode(key.currency0, key.currency1, recipient);

      IPositionManagerV4(_asset).modifyLiquidities(abi.encode(actions, params), block.timestamp);

      amount0 = _currencyBalance(key.currency0, recipient) - balance0Before;
      amount1 = _currencyBalance(key.currency1, recipient) - balance1Before;
    }

    emit FeesCollected(amount0, amount1);
  }

  /// @dev Balance of `account_` in `currency_` - native ETH (`address(0)`, the
  /// V4 convention) or an ERC20 token, whichever this pool's currency is.
  function _currencyBalance(address currency_, address account_) private view returns (uint256) {
    return currency_ == address(0) ? account_.balance : IERC20(currency_).balanceOf(account_);
  }

  // --- vesting release ---

  /// @notice Amount vested by `timestamp` under the linear schedule: nothing
  /// before the cliff, then `total * (t - start) / (end - start)`, capped at
  /// `total` from `end` onward.
  function _vestedAt(uint40 timestamp_) private view returns (uint256) {
    if (timestamp_ < _vestCliff) return 0;
    if (timestamp_ >= _vestEnd) return _vestTotal;
    return (_vestTotal * (timestamp_ - _vestStart)) / (_vestEnd - _vestStart);
  }

  /// @notice Total granted amount that has vested as of now.
  function vestedAmount() public view returns (uint256) {
    return _vestedAt(uint40(block.timestamp));
  }

  /// @notice Amount already released to the owner.
  function releasedAmount() external view returns (uint256) {
    return _released;
  }

  /// @notice Amount claimable right now: the vested-but-unreleased amount,
  /// never more than the tokens actually held (fee-on-transfer safe).
  function releasable() public view returns (uint256) {
    uint256 ideal = vestedAmount() - _released;
    uint256 held = _isFungible() ? IERC20(_asset).balanceOf(address(this)) : 0;
    return ideal < held ? ideal : held;
  }

  /// @notice The vesting schedule and nominal grant (vesting locks only).
  function getVesting() external view returns (uint40 start, uint40 cliff, uint40 end, uint256 total, uint256 released) {
    return (_vestStart, _vestCliff, _vestEnd, _vestTotal, _released);
  }

  /// @notice Release the currently-claimable vested tokens to the owner.
  /// Effects (bump `_released`) precede the transfer - checks-effects-interactions.
  function release() external onlyOwner onlyVesting nonReentrant returns (uint256 amount) {
    amount = releasable();
    _released += amount;
    IERC20(_asset).safeTransfer(_owner(), amount);
    emit TokensReleased(amount);
  }

  // --- withdrawal (after unlock) ---

  /// @dev Return the locked asset to the owner once the lock has matured.
  /// Vesting locks release via `release()` instead, so they are rejected here.
  function withdraw() external onlyOwner nonReentrant {
    if (_kind == ITitanLockerManagerV2.LockKind.ERC20_VESTING) revert WrongLockKind();
    if (uint40(block.timestamp) < _unlockTime) revert LockStillActive(_unlockTime);

    if (_kind == ITitanLockerManagerV2.LockKind.ERC20) {
      IERC20(_asset).safeTransfer(_owner(), _heldBalance());
      emit TokensWithdrawn();
    } else {
      IERC721(_asset).safeTransferFrom(address(this), _owner(), _tokenId);
      emit PositionWithdrawn(_tokenId);
    }
  }

  // --- rescue (stray assets that are not the locked one) ---

  /// @dev Rescue any ERC20 other than an ERC20-lock's locked token (e.g. an
  /// airdrop or dividend). For NFT locks nothing is excluded - the locked asset
  /// is an NFT, not an ERC20, so this can never move it.
  function withdrawToken(address tokenAddress_) external onlyOwner nonReentrant {
    if (_isFungible() && tokenAddress_ == _asset) revert CannotSweepLockedToken();

    IERC20 stray = IERC20(tokenAddress_);
    stray.safeTransfer(_owner(), stray.balanceOf(address(this)));
  }

  /// @dev Rescue an ERC721 that landed on this contract by mistake. The locked
  /// position NFT itself can never be moved this way - it is only releasable via
  /// `withdraw()` after `unlockTime` - so this only ever frees genuinely stray
  /// NFTs (the contract accepts any NFT via ERC721Holder, so without this they
  /// would be stuck forever).
  function withdrawNft(address collection_, uint256 tokenId_) external onlyOwner nonReentrant {
    if (_kind != ITitanLockerManagerV2.LockKind.ERC20 && collection_ == _asset && tokenId_ == _tokenId) {
      revert CannotSweepLockedToken();
    }
    IERC721(collection_).safeTransferFrom(address(this), _owner(), tokenId_);
    emit StrayNftRescued(collection_, tokenId_);
  }

  /// @dev Rescue any ETH that landed on this contract (e.g. from a dividend token).
  function withdrawEth() external onlyOwner nonReentrant {
    (bool success, ) = payable(_owner()).call{value: address(this).balance}("");
    if (!success) revert EthTransferFailed();
  }

  function _transferOwnership(address newOwner_) internal override onlyOwner {
    address previousOwner = _owner();
    super._transferOwnership(newOwner_);

    // keep the manager's search index in sync with the new owner
    _manager.notifyLockerOwnerChange(_id, newOwner_, previousOwner, _createdBy);
  }

  /// @dev Accepts stray ETH (e.g. dividends); use `withdrawEth` to recover it.
  receive() external payable {}
}

